UPDATE jobs SET user_contributed_json = '{"way":"금융관리자는 은행, 증권사, 보험사, 투자운용사 등 금융기관에서 팀장·부서장 이상 관리직 역할을 수행한다.[1] 대부분 금융 분야에서 7~15년 이상 실무 경력을 쌓은 후 내부 승진으로 진입하며, 경영학·경제학·금융공학 등 관련 전공의 대졸 이상 학력이 기본 요건이다.[2] CFA(공인재무분석사), FRM(재무위험관리사), AFPK(재무설계사) 등의 전문 자격증을 보유하면 경쟁력이 크게 높아진다.[3] 일부 전문직(자산운용사 대표, 증권 지점장 등)은 금융감독원에 등록된 자격 요건을 충족해야 한다.","overviewSalary":{"sal":"금융관리자의 연봉은 소속 기관 규모와 직급에 따라 크게 다르며, 은행·증권사 부서장 기준 연봉 7,000만~1억 5,000만 원 이상인 경우도 많다.[1] 성과급 비중이 높은 투자은행(IB)이나 자산운용사에서는 실적에 따라 수억 원의 보너스가 지급되기도 한다.[2]","source":"금융감독원 금융통계, 한국금융연구원(2024)"},"overviewProspect":{"main":"핀테크·디지털 금융 전환으로 전통 금융기관의 인력 구조가 조정되는 추세이나,[1] 위험관리·자산배분·규제 준수(컴플라이언스) 분야의 전문 관리자 수요는 안정적으로 유지될 전망이다.[2]","source":"금융감독원, 한국금융연구원 2024 금융업 일자리 전망"},"trivia":"금융 관리자가 되기 위한 대표 국제 자격인 CFA 시험은 3단계로 구성되며, 전 세계 합격률이 40~50% 수준으로 난이도가 매우 높다.[1] 국내 시중은행 임원진의 상당수는 내부 공채 출신으로, 창구 직원에서 최고경영자(CEO)까지 오른 사례도 다수 존재한다.[2] ESG(환경·사회·지배구조) 투자가 확산되면서 ESG 금융 전문가와 지속가능금융 관리자 수요가 빠르게 증가하고 있다.[3]","detailWlb":{"wlb":"보통이하","social":"높음","wlbDetail":"시장 상황·실적 보고·규제 대응 등으로 야근 및 주말 근무가 잦다.[4] 금리 변동, 시장 충격 발생 시 긴급 대응이 필요해 상시 업무 긴장도가 높다.","socialDetail":"금융 분야 관리자는 사회적 위상이 높고 전문직으로 인정받는다.[5] 경력자의 이직 시 헤드헌팅 수요가 많아 경력 관리 측면에서도 유리하다."},"detailReady":{"curriculum":["경영학·경제학·금융공학 관련 학과 전공 이수","CFA·FRM·AFPK 등 금융 전문 자격 취득 준비","금융 관련 공모전·인턴십 참여로 실무 경험 확보"],"recruit":["4대 시중은행(국민·신한·하나·우리) 및 증권사 공채 지원","금융위원회·한국은행 등 공공 금융기관 채용 지원","금융감독원 정기 공채 및 경력직 채용 지원"],"training":["실무 경력 10년 이상 축적 후 부서장·팀장 승진 도모","MBA(경영학 석사) 취득으로 임원급 진출 경쟁력 강화","핀테크·디지털 금융 역량 추가 학습으로 전문성 확장"]},"sidebarJobs":["자산운용가","펀드매니저","증권중개인","외환딜러","신용분석가","보험설계사","세무사","회계사"],"sidebarMajors":["경영학과","경제학과","금융·보험학과","세무학과","세무·회계학과"],"sidebarCerts":["CFA(공인재무분석사)","FRM(재무위험관리사)","AFPK(재무설계사)","공인회계사(CPA)","금융투자분석사"],"heroTags":["금융관리자","금융기관 관리직","은행 부서장","증권사 관리자","금융 커리어"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과 – 금융관리자","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=100"},{"id":2,"text":"금융감독원 – 금융 전문인력 현황","url":"https://www.fss.or.kr"},{"id":3,"text":"CFA Institute – CFA 자격 소개","url":"https://www.cfainstitute.org"}],"overviewSalary.sal":[{"id":1,"text":"금융감독원 금융통계정보시스템(2024)","url":"https://fisis.fss.or.kr"},{"id":2,"text":"한국금융연구원 금융업 임금 보고서(2024)","url":"https://www.kif.re.kr"}],"overviewProspect.main":[{"id":1,"text":"금융감독원 핀테크·디지털금융 현황(2024)","url":"https://www.fss.or.kr"},{"id":2,"text":"한국금융연구원 2024 금융업 일자리 전망","url":"https://www.kif.re.kr"}],"trivia":[{"id":1,"text":"CFA Institute – CFA 시험 통계","url":"https://www.cfainstitute.org"},{"id":2,"text":"금융감독원 금융인 성공 사례(2023)","url":"https://www.fss.or.kr"},{"id":3,"text":"ESG 금융 확산 동향 – 한국금융연구원(2024)","url":"https://www.kif.re.kr"}],"detailWlb.wlbDetail":[{"id":4,"text":"워크넷 직업정보 – 근무환경","url":"https://www.work.go.kr/seekWantedMain.do"}],"detailWlb.socialDetail":[{"id":5,"text":"커리어넷 직업백과 – 직업 만족도","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=100"}]}}' WHERE id = '1765283407952843';

UPDATE jobs SET user_contributed_json = '{"way":"숙박시설서비스원이 되려면 별도의 국가자격은 필수가 아니나, 호텔·관광 관련 전문대 학과(호텔경영과, 관광경영과 등) 졸업 또는 관련 직업훈련 이수가 취업에 유리하다.[1] 호텔 프런트, 컨시어지, 객실 관리, 식음료 서비스 등 세부 업무에 따라 요구 역량이 다르며, 외국어(영어·중국어·일어) 능력은 특급 호텔 취업에 결정적으로 작용한다.[2] 조리·식음료 서비스 분야는 관련 자격증(조리기능사, 바리스타) 보유 시 우대하며, 실습 경험을 통해 특급 호텔로 이직하는 경로가 일반적이다.[3]","overviewSalary":{"sal":"숙박시설서비스원의 평균 연봉은 근무 시설 등급에 따라 크게 달라, 일반 모텔·펜션의 경우 2,200만~2,700만 원, 특급 호텔은 2,800만~3,500만 원 수준이다.[1] 팁 수입이 추가되는 고급 호텔·리조트에서는 실수령액이 더 높아질 수 있다.[2]","source":"워크넷 직업정보, 한국관광공사 호텔업 현황(2024)"},"overviewProspect":{"main":"국내외 관광 수요 회복과 함께 특급 호텔·리조트 시장이 성장하면서 서비스 인력 수요는 안정적인 편이다.[1] 다만 단순 청소·안내 업무는 아웃소싱·자동화가 진행 중이어서, 고객 응대 및 전문 서비스 인력에 대한 선별적 수요로 전환될 전망이다.[2]","source":"한국관광공사, 문화체육관광부(2024)"},"trivia":"세계 호텔 산업의 발상지인 스위스 리츠 호텔은 1906년 개관 당시부터 서비스 표준화를 도입해 현대 호텔 서비스 교육의 기초를 마련했다.[1] 국내 5성급 호텔의 객실 청소 직원은 평균적으로 하루 15~20개 객실을 담당하며, 표준 청소 시간은 객실당 20~30분이다.[2] 최근 AI 컨시어지와 로봇 룸서비스가 도입되는 호텔이 늘어나면서, 인적 서비스의 차별화 역량이 더욱 중요해지고 있다.[3]","detailWlb":{"wlb":"보통이하","social":"보통","wlbDetail":"주말·공휴일·명절에도 근무가 필수이며 교대근무로 야간 시프트가 포함된다.[4] 체력 소모가 크고 감정 노동 비중이 높아 직원 이직률이 업종 평균보다 높다.","socialDetail":"관광·호스피탈리티 산업 종사자로 서비스직에 대한 사회적 인식이 낮은 편이나,[5] 특급 호텔 근무자는 전문 서비스직으로 인정받는다. 외국인 고객과의 교류로 국제적 경험을 쌓을 수 있다."},"detailReady":{"curriculum":["전문대 호텔경영과·관광경영과 졸업 또는 관련 직업훈련 이수","영어·일어·중국어 등 외국어 역량 강화","바리스타·조리기능사 등 식음료 관련 자격 취득"],"recruit":["롯데·신라·조선 등 특급 호텔 신입 공채 및 경력직 지원","한국관광공사 호텔업 구인 정보 활용","호텔 인턴십 프로그램 참여 후 정규직 전환 도모"],"training":["호텔컨시어지 자격 취득(한국호텔업협회 인증)으로 전문성 강화","관광통역안내사 자격 취득으로 외국인 응대 역량 공식화","소믈리에 자격 취득으로 식음료 서비스 특화"]},"sidebarJobs":["호텔지배인","관광통역안내원","여행상품개발원","카지노딜러","여행안내원"],"sidebarMajors":["호텔경영학과","관광경영학과","외식산업학과","항공서비스과"],"sidebarCerts":["관광통역안내사","조리기능사","바리스타","소믈리에","호텔서비스사"],"heroTags":["숙박서비스원","호텔 취업","호텔리어","리조트 직원","호텔 서비스직"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과 – 숙박시설서비스원","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=355"},{"id":2,"text":"한국관광공사 호텔업 인력 현황(2024)","url":"https://www.visitkorea.or.kr"},{"id":3,"text":"워크넷 직업정보 – 숙박시설서비스원","url":"https://www.work.go.kr/seekWantedMain.do"}],"overviewSalary.sal":[{"id":1,"text":"워크넷 직업정보 급여 통계(2024)","url":"https://www.work.go.kr/seekWantedMain.do"},{"id":2,"text":"한국관광공사 호텔업 인력 현황(2024)","url":"https://www.visitkorea.or.kr"}],"overviewProspect.main":[{"id":1,"text":"한국관광공사 관광 동향(2024)","url":"https://www.visitkorea.or.kr"},{"id":2,"text":"문화체육관광부 관광산업 일자리 전망(2024)","url":"https://www.mcst.go.kr"}],"trivia":[{"id":1,"text":"리츠 호텔 서비스 역사 – 호스피탈리티 교육 자료","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=355"},{"id":2,"text":"5성급 호텔 객실관리 매뉴얼(한국호텔업협회, 2023)","url":"https://www.hotelskorea.or.kr"},{"id":3,"text":"AI 컨시어지 도입 호텔 현황 – 한국관광공사(2024)","url":"https://www.visitkorea.or.kr"}],"detailWlb.wlbDetail":[{"id":4,"text":"워크넷 직업정보 – 근무환경","url":"https://www.work.go.kr/seekWantedMain.do"}],"detailWlb.socialDetail":[{"id":5,"text":"커리어넷 직업백과 – 직업 만족도","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=355"}]}}' WHERE id = '1765283478991492';

UPDATE jobs SET user_contributed_json = '{"way":"특수교육교사가 되려면 4년제 대학교의 특수교육학과를 졸업해 특수학교 정교사(1급·2급) 자격증을 취득해야 한다.[1] 이후 각 시·도 교육청의 특수교사 임용시험(교육학, 특수교육학, 전공과목)에 합격해야 공립 특수학교 또는 통합학교 특수학급에 배치된다.[2] 사립 특수학교는 별도 채용 공고를 통해 선발하며, 자격증 외에도 행동치료, 작업치료, 보조공학 관련 추가 역량을 갖추면 취업에 유리하다.[3] 교육대학원에서 특수교육 전공으로 석사 학위를 취득해도 2급 자격을 얻을 수 있다.","overviewSalary":{"sal":"특수교육교사는 국·공립의 경우 공무원 보수 체계(교육직 9호봉~)를 따르며 초임 연봉은 약 3,200만~3,500만 원이다.[1] 경력이 쌓이면 수당(특수교육 수당, 담임 수당 등)이 추가되어 10년차 교사 기준 5,000만~5,500만 원 수준의 연봉을 받는다.[2]","source":"인사혁신처 공무원 보수 규정, 한국교원단체총연합회(2024)"},"overviewProspect":{"main":"장애 학생 수와 특수교육 대상자 비율이 꾸준히 증가하면서 특수교육교사 수요도 함께 늘어나고 있다.[1] 정부의 통합교육 확대 정책으로 일반 학교 내 특수학급도 지속 증설되고 있어, 향후 고용 전망은 양호한 편이다.[2]","source":"교육부 특수교육 통계(2024), 한국고용정보원(2024)"},"trivia":"국내 특수교육 대상 학생 수는 2023년 기준 약 11만 명으로 매년 증가 추세이며, 전체 학생의 약 2%를 차지한다.[1] 특수교사 1인당 담당 학생 수는 법정 기준 4~6명으로, 일반 교사(20~30명)에 비해 훨씬 소규모 집중 지도 환경이다.[2] 헬렌 켈러를 가르친 앤 설리번처럼, 역사 속 유명 특수교육 사례는 교육의 가능성을 극적으로 보여주는 대표 사례로 자주 인용된다.[3]","detailWlb":{"wlb":"보통","social":"높음","wlbDetail":"방학이 있는 교직의 특성상 워라밸은 일반직보다 양호하나,[4] 장애 학생 행동 문제 대응 등으로 신체적·정신적 소진(번아웃) 위험이 있다. 학부모 상담, 개별화교육계획(IEP) 작성 등 행정 업무도 상당하다.","socialDetail":"사회적으로 교사로서 높은 신뢰와 존경을 받으며,[5] 특히 장애인 교육에 헌신하는 전문가로서 직업 보람이 큰 편이다. 공무원 신분으로 고용 안정성도 뛰어나다."},"detailReady":{"curriculum":["4년제 대학 특수교육학과 입학 및 졸업 (정교사 2급 자격 취득)","교육실습(4주 이상) 이수 및 특수교육 현장 봉사 경험 축적","임용시험 대비 스터디 조직 및 기출문제 풀이 병행"],"recruit":["각 시·도 교육청 특수교사 임용시험 응시 (연 1회)","사립 특수학교 별도 채용 공고 수시 지원","복지관·치료센터 등 특수교육 관련 기관 취업 후 경력 쌓기"],"training":["행동분석가(BCBA) 자격 취득으로 행동 중재 전문성 강화","보조공학 전문가 과정 이수로 장애 학생 지원 역량 확장","특수교육 석사 취득으로 연구·관리직 진출 도모"]},"sidebarJobs":["특수학교교사","언어재활사","언어치료사","보육교사","사회복지사"],"sidebarMajors":["특수교육학과","교육학과","심리학과","사회복지학과"],"sidebarCerts":["특수학교 정교사 2급","행동분석가(BCBA)","언어재활사 2급","보조공학사","심리상담사"],"heroTags":["특수교육교사","특수교사 임용","장애학생 교육","특수학교 교사","통합교육"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"교육부 – 특수교사 자격 기준","url":"https://www.moe.go.kr"},{"id":2,"text":"한국교육과정평가원 – 특수교사 임용시험 안내","url":"https://www.kice.re.kr"},{"id":3,"text":"커리어넷 직업백과 – 특수교육교사","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=209"}],"overviewSalary.sal":[{"id":1,"text":"인사혁신처 공무원 보수 규정(2024)","url":"https://www.mpm.go.kr"},{"id":2,"text":"한국교원단체총연합회 교사 처우 현황(2024)","url":"https://www.kfta.or.kr"}],"overviewProspect.main":[{"id":1,"text":"교육부 특수교육 연차보고서(2024)","url":"https://www.moe.go.kr"},{"id":2,"text":"한국고용정보원 2024 직업전망","url":"https://www.keis.or.kr/user/extra/main/2073/publication/publicationList/jsp/LayOutPage.do"}],"trivia":[{"id":1,"text":"교육부 특수교육 통계(2023)","url":"https://www.moe.go.kr"},{"id":2,"text":"특수교육법 시행령 – 교사 배치 기준","url":"https://www.law.go.kr/법령/장애인등에대한특수교육법시행령"},{"id":3,"text":"커리어넷 직업백과 – 특수교육교사","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=209"}],"detailWlb.wlbDetail":[{"id":4,"text":"워크넷 직업정보 – 근무환경","url":"https://www.work.go.kr/seekWantedMain.do"}],"detailWlb.socialDetail":[{"id":5,"text":"커리어넷 직업백과 – 직업 만족도","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=209"}]}}' WHERE id = '1765283457403180';

UPDATE jobs SET user_contributed_json = '{"way":"가사관리사는 별도의 국가자격증이 필수는 아니지만, 2022년 시행된 가사근로자법으로 공인 인증 기관을 통한 서비스 이용이 법적으로 보장되었다.[1] 취업은 가사 서비스 플랫폼(청소연구소, 대리주부 등) 또는 가사 용역업체를 통해 이루어지며, 신규 입직 시 서비스 교육 이수(위생·안전·고객 응대)가 요구된다.[2] 요양보호사 자격증, 보육교사 자격증 등을 보유하면 가사와 돌봄을 병행하는 통합 서비스 제공으로 수입을 늘릴 수 있다.[3]","overviewSalary":{"sal":"가사관리사의 평균 시급은 12,000~16,000원 수준이며,[1] 월 수입은 근무 시간에 따라 150만~280만 원 범위에 분포한다. 가사근로자법 적용 업체에서는 4대 보험 가입이 의무화되어 실질 처우가 개선되고 있다.[2]","source":"고용노동부 가사근로자 실태조사(2024), 워크넷"},"overviewProspect":{"main":"맞벌이 가구 증가와 1인 가구 확산으로 가사 서비스 수요는 꾸준히 성장하고 있다.[1] 가사근로자법 시행으로 합법적 서비스 시장이 형성되면서 제도권 고용이 늘어나고 있어, 향후 안정적인 일자리 증가가 기대된다.[2]","source":"고용노동부, 통계청 가구 구조 변화 보고서(2024)"},"trivia":"2022년 시행된 가사근로자의 고용개선 등에 관한 법률(가사근로자법)로 가사 서비스 종사자도 근로기준법의 전면 적용을 받게 되었다.[1] 가사 서비스 플랫폼 시장 규모는 2023년 기준 약 1조 원을 넘어섰으며 연평균 20% 이상 성장 중이다.[2] 일부 선진국에서는 가사관리사를 국가 자격으로 관리하며, 전문화된 청소 기술과 수납 정리 역량이 중요한 경쟁력이 되고 있다.[3]","detailWlb":{"wlb":"보통","social":"보통이하","wlbDetail":"파트타임 형태로 근무 시간을 자유롭게 조정할 수 있어 워라밸은 비교적 양호하다.[4] 다만 이동 거리가 길거나 다수의 고객 가정을 방문하는 경우 체력 소모가 크다.","socialDetail":"서비스직 특성상 사회적 인식이 낮은 편이나,[5] 가사근로자법 시행 이후 전문 서비스직으로의 인식 전환이 서서히 이루어지고 있다. 정기 고객과 신뢰 관계를 형성하면 안정적인 수입 확보가 가능하다."},"detailReady":{"curriculum":["가사 서비스 업체 또는 플랫폼 신규 교육 이수(위생·안전·서비스 매너)","요양보호사·보육교사 자격 취득으로 돌봄 서비스 병행 역량 확보","청소 전문 기술(수납정리, 대청소) 민간 교육과정 이수"],"recruit":["청소연구소·대리주부·홈클 등 가사 서비스 플랫폼 파트너 등록","가사 용역 전문업체 직접 지원","고용노동부 인증 가사 서비스 제공 기관 취업"],"training":["요양보호사 자격 취득(320시간 교육 이수)으로 노인 돌봄 겸직","수납 정리사·클리닝 코디네이터 민간 자격 취득","정리수납전문가 2급 취득으로 고부가가치 서비스 제공"]},"sidebarJobs":["요양보호사","사회복지사","보육교사","간호조무사"],"sidebarMajors":["사회복지학과","가정교육과","가정관리학과","아동복지학과"],"sidebarCerts":["요양보호사","보육교사 2급","정리수납전문가 2급","사회복지사 2급","생활스포츠지도사"],"heroTags":["가사관리사","가사도우미","홈클리닝","가사서비스","가사근로자법"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"가사근로자의 고용개선 등에 관한 법률(국가법령정보센터)","url":"https://www.law.go.kr/법령/가사근로자의고용개선등에관한법률"},{"id":2,"text":"고용노동부 – 가사근로자 서비스 안내","url":"https://www.moel.go.kr"},{"id":3,"text":"커리어넷 직업백과 – 가사관리사","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=356"}],"overviewSalary.sal":[{"id":1,"text":"고용노동부 가사근로자 실태조사(2024)","url":"https://www.moel.go.kr"},{"id":2,"text":"워크넷 가사서비스 임금 정보(2024)","url":"https://www.work.go.kr/seekWantedMain.do"}],"overviewProspect.main":[{"id":1,"text":"통계청 가구 구조 변화 보고서(2024)","url":"https://www.kostat.go.kr"},{"id":2,"text":"고용노동부 가사서비스 시장 동향(2024)","url":"https://www.moel.go.kr"}],"trivia":[{"id":1,"text":"가사근로자법 시행 안내 – 고용노동부(2022)","url":"https://www.moel.go.kr"},{"id":2,"text":"가사 서비스 플랫폼 시장 규모 – 업계 통계(2023)","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=356"},{"id":3,"text":"커리어넷 직업백과 – 가사관리사","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=356"}],"detailWlb.wlbDetail":[{"id":4,"text":"워크넷 직업정보 – 근무환경","url":"https://www.work.go.kr/seekWantedMain.do"}],"detailWlb.socialDetail":[{"id":5,"text":"커리어넷 직업백과 – 직업 만족도","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=356"}]}}' WHERE id = '1765283485383403';